"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[717],{4502:function(e,i,t){t.d(i,{cn:function(){return n}});var s=t(1994),r=t(3335);function n(){for(var e=arguments.length,i=Array(e),t=0;t<e;t++)i[t]=arguments[t];return(0,r.m6)((0,s.W)(i))}},8055:function(e,i,t){t.d(i,{L:function(){return s},l:function(){return r}});let s=[{title:"Корпоративные мероприятия",slug:"korporativnye-meropriyatiya"},{title:"Тимбилдинг",slug:"timbilding"},{title:"Деловые мероприятия",slug:"delovye-meropriyatiya"},{title:"Рекламные акции",slug:"reklamnye-akcii"},{title:"Аренда реквизита",slug:"arenda-rekvizita"}],r={"korporativnye-meropriyatiya":{slug:"korporativnye-meropriyatiya",title:"Корпоративные мероприятия в Новосибирске",shortDescription:"Мероприятия, укрепляющие личные и деловые связи, профессиональную коммуникацию между участниками, и формирующие лояльность к компании.",heroImage:{src:"/services/korporativnye-meropriyatiya.webp",alt:"Корпоративные мероприятия — event-агентство Закулисье Новосибирск",blurDataURL:"data:image/webp;base64,UklGRlQAAABXRUJQVlA4IEgAAADwAQCdASoMAAgABABoJagCdADhlAihigAA/vS0inxXU5SCbTTUqMc2I+1Md9fVLnjMeQop85DxDCOi63+0KoLngdemsYoAAAA=",width:1600,height:1067},includes:[{title:"Концепция и сценарий",description:"Глубокое погружение в потребности заказчика, в историю предприятия и разработка авторской уникальной программы."},{title:"Подбор команды подрядчиков",description:"От выбора локации до брендированных подарков. Мы работаем с лучшими исполнителями по всему сибирскому региону."},{title:"Координация проекта",description:"Сопровождение всех служб на этапе подготовки проекта и во время его реализации."}],whyUs:[{title:"",description:"Многие наши клиенты ежегодно вкладывают деньги в развитие корпоративной культуры и часто ставят во главу угла просто отдых своих сотрудников. Мы же предлагаем эффективно использовать это время для того, чтобы корпоративное мероприятие, кроме развлечения, также принесло пользу компании. Например, найти и отметить сотрудников, на которых стоит ориентироваться не только по трудовым показателям, но и по другим важным характеристикам. Транслировать ценности, создавать отношения, узнавать друг друга. Если клиент даёт нам такую возможность, мы едем на производство и изнутри смотрим, как работает компания. Мы проводим интервью с сотрудниками и собираем ценную информацию, благодаря которой программа корпоратива становится уникальной."}],faq:[{question:"Из чего складывается стоимость ваших услуг?",answer:"Смета расходов состоит из трёх основных позиций: чистая стоимость услуг всех исполнителей, услуги агентства по подбору и координации работы подрядчиков, налоги и расчётно-кассовые операции."},{question:"Может ли клиент взять часть работы на себя?",answer:"Да, может. Важно понимать, что мы работаем в комплексе, и участие третьих лиц в этом процессе может негативно отразиться на качестве, поэтому мы рекомендуем полностью довериться нам."},{question:"Сколько нужно времени на подготовку мероприятия?",answer:"Подготовка мероприятия за 5–6 месяцев предоставляет нам большой выбор исполнителей, в сжатые же сроки мы в выборе ограничены. Мы всегда найдём решение и сделаем для вас лучший праздник, но в спокойном режиме и при достаточном времени у нас больше возможностей."},{question:"Нужно ли участие клиента в организации процессов?",answer:"Да, но только на этапе согласований и ответов на наши вопросы. Всю организационную работу мы возьмём на себя."}],seoTitle:"Организация корпоративных мероприятий | Закулисье",seoDescription:"Организация корпоративных мероприятий в Новосибирске и Сибири: сценарий, площадка, техника, команда сопровождения. Для компаний, где важна репутация.",quote:{text:"Нам нужен был спокойный процесс при большом количестве гостей. Получили ровно это — и визуально, и организационно.",author:"[Имя]",position:"Директор по персоналу",company:"[Промышленный холдинг]"}},timbilding:{slug:"timbilding",title:"Тимбилдинг для компаний в Сибири",shortDescription:"Проекты, направленные на тренировку командного взаимодействия, анализ сильных и слабых мест в команде.",heroImage:{src:"/services/timbilding.webp",alt:"Тимбилдинг — event-агентство Закулисье Новосибирск",blurDataURL:"data:image/webp;base64,UklGRloAAABXRUJQVlA4IE4AAADwAQCdASoMAAgABABoJZACdAEQeyDq8KAA/rI6/EFBS2fbP0z0FohmRsalMgZOlW/a1KQOu+JJn9kkTmOc1TeHlmkCboSVLrrwePGAAAA=",width:1600,height:1067},includes:[{title:"Игровой тематический тимбилдинг или спартакиада",description:"Самый привычный формат. Выездное спортивное мероприятие с сюжетом и командными соревнованиями, скорее всего на улице."},{title:"Верёвочный курс",description:"Глубокое погружение в командное взаимодействие через активные упражнения."},{title:"Командообразующий тренинг",description:"Живое игровое взаимодействие через импровизацию и речевую коммуникацию."}],whyUs:[{title:"",description:"Мы уже несколько лет изучаем тему командообразования и сами проходим множество обучающих программ. Мы опираемся не только на творчество, но и в первую очередь на психологию коллективного взаимодействия. Командообразующее мероприятие — это работа коллектива, в которой на поверхность выносятся ценности именно командного взаимодействия. Игры и упражнения устроены таким образом, чтобы никто не смог перетянуть одеяло на себя, и наоборот — чтобы позволить отпустить руль и довериться коллегам. Через юмор, соревнования, глубинные упражнения, игры, верёвочные курсы мы учим ваших сотрудников: делегировать, доверять, слушать друг друга, чётко ставить задачи и многое другое."}],faq:[{question:"Подходит ли такой формат интровертам?",answer:"Да, подходит. Как и в обычной жизни, все мы взаимодействуем по работе с разными людьми, и командообразующие упражнения позволяют отследить эффективность взаимодействия сразу и точно."},{question:"Можно ли провести на территории заказчика?",answer:"Если площадка отвечает всем правилам пожарной безопасности, а также соответствует всем запросам мероприятия, конечно можно."},{question:"Как измерить эффект?",answer:"После таких мероприятий критически важно собирать обратную связь с участников, чтобы увидеть, какие открытия они совершили во время этой работы, и смотреть на трудовые показатели в течение 5–6 месяцев после проекта."},{question:"Работаете ли вы зимой на открытых площадках?",answer:"Да, ведь зима — отличное время для проведения открытых командообразующих мероприятий. Исключён дождь, и участники больше сосредоточены на работе, чем летом. Летний вайб отвлекает от работы."}],seoTitle:"Тимбилдинг и командные мероприятия | Закулисье",seoDescription:"Тимбилдинг в Новосибирске и Сибири: форматы для зрелых команд, фасилитация, безопасность и измеримый результат для HR."},"delovye-meropriyatiya":{slug:"delovye-meropriyatiya",title:"Деловые мероприятия и конференции в Новосибирске",shortDescription:"События, направленные на развитие профессиональных компетенций. Конкурсы профессионального мастерства, обучающие форумы, мастер-классы, конференции, семинары, съезды дилеров, стратегические сессии.",heroImage:{src:"/services/delovye-meropriyatiya.webp",alt:"Деловые мероприятия — event-агентство Закулисье Новосибирск",blurDataURL:"data:image/webp;base64,UklGRlQAAABXRUJQVlA4IEgAAACwAQCdASoMAAgABABoJZACdADZkRowAP7PdWhNz5E8pZvmP4zusnjh6K6UonLlrIO0nTgvcVCuM5AEfq+4vKx+zuR57JGgAAA=",width:1600,height:1067},includes:[{title:"Знакомство дилеров с особенностями продукта и его продвижения",description:"Через тестирование, обучение, экскурсии на предприятие и неформальные встречи с руководителями отделов продаж."},{title:"Выявление лучших сотрудников и формирование трудовых ориентиров",description:"Через конкурсы профессионального мастерства, через демонстрацию навыков и поощрение лучших."},{title:"Обучение персонала и трансляция ценностей",description:"Через проведение лекционных и практических занятий, формирование здоровой конкуренции и поощрение любопытства."}],whyUs:[{title:"",description:"Мы специализируемся на коммерческих мероприятиях и совсем не делаем частные проекты. Мы точно знаем, что такое бизнес, конкуренция и деловые связи. Мы ценим время, выделенное для мероприятия, и используем его эффективно. Организация деловых проектов — это смесь менеджмента, психологии и режиссуры, и каждый из этих навыков одинаково важен, а мы отлично владеем всеми тремя."}],faq:[{question:"Помогаете ли вы формулировать бизнес-задачи?",answer:"Да, мы делаем это прежде, чем формировать смету и коммерческое предложение. Многим нашим клиентам такая работа помогает шире увидеть свой запрос и понять ценность мероприятия."},{question:"Кто ищет спикеров для проведения обучения?",answer:"Это происходит обоюдно. Есть общие компетенции, а есть узкоспециализированные, и конечно, нашим клиентам проще оценить уровень знаний спикера, если речь идёт об узкой специализации. Однако мы много сотрудничаем с самыми разными образовательными платформами и можем сформировать очень эффективное обучение. В любом случае все организационные вопросы мы возьмём на себя."},{question:"Как формируются критерии оценки профессионального мастерства?",answer:"Порой это увлекательный творческий процесс, включаясь в который наш клиент откроет для себя много нового о своём бизнесе. Если такие критерии есть в компании — это очень здорово, если же нет — мы зададим правильные вопросы и сформируем их вместе."},{question:"Делаете ли вы отчёт по итогам мероприятия?",answer:"Да, это отдельная услуга и очень полезная документация для нашего заказчика. Выводы, собранные в таблицу с анализом данных, дают ясную картину, с которой очень удобно работать в дальнейшем."}],seoTitle:"Организация деловых мероприятий | Закулисье",seoDescription:"Деловые мероприятия в Новосибирске: форумы, съезды, сессии. Тайминг, трансляции, сервис участников и управлениерисками."},"reklamnye-akcii":{slug:"reklamnye-akcii",title:"Рекламные акции и бренд‑активации",shortDescription:"События, направленные на продвижение товаров и услуг или самого бренда, стимулирующие к покупке, и формирующие лояльность покупателей. Презентации, промо-акции, открытия или дни рождения магазинов, ТЦ, фестивали и многое другое.",heroImage:{src:"/services/reklamnye-akcii.webp",alt:"Рекламные акции и активации — event-агентство Закулисье Новосибирск",blurDataURL:"data:image/webp;base64,UklGRmAAAABXRUJQVlA4IFQAAAAwAgCdASoMAAgABABoJbACdH8AglCbzG5EZAD+h7SDMH8dIxVNhX/enec6Y5AEZBDlNBk/sgPSthlRSOnPa82G/E8xxZp0llnHmjahUT/OsoGAAAA=",width:1280,height:851},includes:[{title:"Знакомство с брендом и целевой аудиторией",description:"Мы погружаемся в продукт, особенности его производства, знакомимся с потребностями ЦА, чтобы разработать наиболее эффективную идею."},{title:"Разработка авторской концепции",description:"Мы используем креатив и специалистов в области PR-стратегий и маркетинга, чтобы идеи были не только творческими, но и работающими."},{title:"Живая реализация идеи",description:"Мы подбираем лучших исполнителей и контролируем процессы производства, пошива промоформы, изготовления маскотов, подбор промоперсонала, уважая каждую мелочь."}],whyUs:[{title:"",description:"Мы более 11 лет работаем с московскими агентствами как субподрядчики, реализуя промомероприятия для федеральных брендов по самым высоким стандартам, и точно знаем, что такое высокий уровень требований. Нас рекомендуют именно за то, что мы можем не только придумать нестандартный работающий рекламный ход, но и реализовать его."}],faq:[{question:"Работаете ли по регламентам торговых центров?",answer:"Да. Готовим пакет заранее и согласуем монтажные окна так, чтобы не конфликтовать с операционными правилами площадки."},{question:"Можно ли масштабировать на несколько городов?",answer:"Да. Выстраиваем единый стандарт и локальные команды сопровождения."},{question:"Как контролируете внешний вид персонала?",answer:"Единый гайд, выездной супервайзер, фото‑контроль смены — по согласованной периодичности."},{question:"Что с юридическими аспектами промо?",answer:"Подключаемся к процессу через вашу юридическую службу: шаблоны согласий, правила конкурсов, требования площадки."}],seoTitle:"Рекламные акции и активации в Новосибирске | Закулисье",seoDescription:"Организация рекламных акций в Новосибирске: персонал, логистика, стандарты качества и долгие форматы без провалов."},"arenda-rekvizita":{slug:"arenda-rekvizita",title:"Аренда реквизита для мероприятий в Новосибирске",shortDescription:"Собственный парк авторского игрового реквизита — для организаторов и корпоративных клиентов, которым нужна живая активность на площадке.",heroImage:{src:"/services/arenda-rekvizita.webp",alt:"Аренда реквизита — event-агентство Закулисье Новосибирск",blurDataURL:"data:image/webp;base64,UklGRk4AAABXRUJQVlA4IEIAAADwAQCdASoMAAgABABoJbACdAEXZ3X+17AA/uf0F7RFJvEDbUarZWcdvZdExefYtC8JK6Fp1PBB3I3Er/deMIulgAA=",width:1600,height:1067},includes:[{title:"Откуда берётся реквизит",description:"Однажды мы поняли, что уже несколько лет изготавливаем авторский игровой реквизит для своих мероприятий, который скучает на складе после проведения проекта. Собрав всё это в единый прайс, решили предложить его не только корпоративным клиентам, но и организаторам нашего города — для которых действует агентская скидка."},{title:"Крупногабаритный реквизит",description:"Гигантский бильярд, гигантский настольный футбол, гигантская игра \xabволк ловит яйца\xbb."},{title:"Малогабаритный реквизит",description:"Надувные кони, ботинки, бабуки и многое другое."},{title:"Готовые программы",description:"Казино и супергерои — готовые интерактивные форматы с реквизитом."}],whyUs:[{title:"Свой парк",description:"Мы не \xabперекидываем заказ\xbb. Мы отвечаем за состояние того, что отгружаем."},{title:"Скорость",description:"Короткие сроки подготовки за счёт внутренних процессов и наличия на складе."},{title:"Понятные условия",description:"Договор, залоговые механики и ответственность — прозрачно, без скрытых пунктов."}],faq:[{question:"Кому подходит аренда?",answer:"Event‑агентствам, корпоративным командам, продакшну — когда нужен готовый визуальный модуль без собственного цеха."},{question:"Можно ли забрать самовывозом?",answer:"Да, при условии согласованной фиксации состояния при выдаче и возврате."},{question:"Есть ли монтажный персонал?",answer:"Да, по отдельному сметному решению — от одного шефа до бригады."},{question:"Работаете ли за пределами Новосибирска?",answer:"Да, логистика рассчитывается индивидуально — Сибирь и межрегиональные направления."}],seoTitle:"Аренда реквизита для мероприятий в Новосибирске | Закулисье",seoDescription:"Аренда реквизита в Новосибирске: декорации, конструкции, логистика и сопровождение для event‑команд и организаторов."}}}}]);